601: func CheckConfig(agentMode, checkSyntaxOnly bool, lintSettings configLintConfig, p parser.Parser, files ...string) int {
602: 	failed := false
603: 	hasErrors := false
604: 
605: 	for _, f := range files {
606: 		ruleFiles, scrapeConfigs, err := checkConfig(agentMode, f, checkSyntaxOnly)
607: 		if err != nil {
608: 			fmt.Fprintln(os.Stderr, "  FAILED:", err)
609: 			hasErrors = true
610: 			failed = true
611: 		} else {
612: 			if len(ruleFiles) > 0 {
613: 				fmt.Printf("  SUCCESS: %d rule files found\n", len(ruleFiles))
614: 			}
615: 			fmt.Printf(" SUCCESS: %s is valid prometheus config file syntax\n", f)
616: 		}
617: 		fmt.Println()
618: 
619: 		if !checkSyntaxOnly {
620: 			scrapeConfigsFailed := lintScrapeConfigs(scrapeConfigs, lintSettings)
621: 			failed = failed || scrapeConfigsFailed
622: 			rulesFailed, rulesHaveErrors := checkRules(ruleFiles, lintSettings.rulesLintConfig, p)
623: 			failed = failed || rulesFailed
624: 			hasErrors = hasErrors || rulesHaveErrors
625: 		}
626: 	}
627: 	if failed && hasErrors {
628: 		return failureExitCode
629: 	}
630: 	if failed && lintSettings.fatal {
631: 		return lintErrExitCode
632: 	}
633: 	return successExitCode
634: }
